tool.example:

multi_step_login(
  steps=[
    {
      "type": "get",
      "url": "https://target.com/login",
      "extract_csrf": true
    },
    {
      "type": "post",
      "url": "https://target.com/login",
      "data": {"username": "admin", "password": "test123"},
      "inject_csrf": true,
      "csrf_field": "csrf_token"
    }
  ],
  session_name="two_step_auth"
)


multi_step_login(
  steps=[
    {
      "type": "post",
      "url": "https://api.target.com/oauth/token",
      "data": {"grant_type": "password", "username": "admin", "password": "test"},
      "content_type": "json",
      "extract_jwt": true
    },
    {
      "type": "get",
      "url": "https://api.target.com/user/profile"
    }
  ]
)
